static size_t s_index = 0;
static uint32_t s_cycle = 0;
static const uint32_t s_start_t = 16067;
/* Span covers [first_sample_ms, last_sample_ms + median_dt_ms) so that
 * loop-around timestamps stay monotonically increasing by roughly one
 * sample period rather than repeating the last t. */
static const uint32_t s_span_t = 9933;  /* last-first + ~median dt */

void dummy_imu_reset(void) {
  s_index = 0;
  s_cycle = 0;
}

bool dummy_imu_next_sample(bno055_sample_t *out) {
  if (!out) {
    return false;
  }

  *out = s_demo_samples[s_index];
  out->t_ms = (out->t_ms - s_start_t) + (s_cycle * s_span_t);

  s_index++;
  if (s_index >= (sizeof(s_demo_samples) / sizeof(s_demo_samples[0]))) {
    s_index = 0;
    s_cycle++;
  }

  return true;
}
